// Función para obtener las armas de una clase específica
function getArmasClase(clase) {
  return ARMAS_UNICAS[clase] || [];
}

// Función para obtener un arma aleatoria de todas las clases
function getArmaAleatoria() {
  const clases  = Object.keys(ARMAS_UNICAS);
  const clase   = clases[Math.floor(Math.random() * clases.length)];
  const armas   = ARMAS_UNICAS[clase];
  const arma    = armas[Math.floor(Math.random() * armas.length)];
  return { ...arma, clase };
}

// Función para obtener un arma aleatoria de la clase del personaje
function getArmaAleatoriaClase(clase) {
  const armas = ARMAS_UNICAS[clase];
  if (!armas?.length) return getArmaAleatoria();
  return { ...armas[Math.floor(Math.random() * armas.length)], clase };
}

module.exports = { ARMAS_UNICAS, getArmasClase, getArmaAleatoria, getArmaAleatoriaClase };
